/// Validate a single ECIES ciphertext blob.
///
/// Empty blobs are allowed because several precompile call paths legitimately supply
/// no encrypted secrets (e.g. sovereign agent calls where the user has no secrets to
/// pass, or FHE calls where DA storage credentials are optional). The on-chain
/// contract handles the empty case; this check only rejects non-empty blobs that
/// are too short to be valid ECIES ciphertext or have the wrong EC point prefix.

/// It does NOT validate TTL, executor address, etc.
///
/// For validation, use `extract_precompile_data` which includes validation.
pub fn try_decode_precompile_data(
    input: &Bytes,
    precompile_address: Address,
) -> Result<(Address, u64), PrecompileDataError> {
    // For HTTP precompile, use HTTPCallRequest decoder
    if precompile_address == HTTP_CALL_PRECOMPILE {
        let http_request = HTTPCallRequest::from_abi(input).map_err(|e| {
            PrecompileDataError::DecodeFailed { details: format!("HTTPCallRequest: {}", e) }
        })?;
        return Ok((http_request.executor, http_request.ttl));
    }

    // For LLM precompile, use LLMCallRequest decoder
    if precompile_address == LLM_CALL_PRECOMPILE {
        let llm_request = LLMCallRequest::from_abi(input).map_err(|e| {
            PrecompileDataError::DecodeFailed { details: format!("LLMCallRequest: {}", e) }
        })?;
        return Ok((llm_request.executor, llm_request.ttl));
    }

/// offset 128 bytes (field 4).
///
/// Returns None if the precompile doesn't have a two-phase deadline or input is too short.
pub fn extract_two_phase_deadline(input: &Bytes, precompile_address: Address) -> Option<u64> {
    // Sovereign Agent has max_poll_block at field 4 (offset 128) - different ABI layout
    if precompile_address == SOVEREIGN_AGENT_PRECOMPILE {
        // Minimum length: at least 5 * 32 = 160 bytes for first 5 fields
        if input.len() < 160 {
            debug!(
                target: "ritual::async::validation",
                input_len = input.len(),
                "Input too short to extract two-phase deadline for Sovereign Agent"
            );
            return None;
        }

        // Field 4 (max_poll_block) is at offset 4 * 32 = 128 bytes
        let offset = 4 * 32;
        let deadline_bytes = &input[offset..offset + 32];

        let deadline_u256 = U256::from_be_slice(deadline_bytes);
        let deadline = deadline_u256.try_into().ok()?;

///
/// The offset must be > TTL to ensure Phase 2 deadline > Phase 1 deadline.
/// (Since settlementBlock >= commitBlock, offset > TTL guarantees the constraint.)
pub fn validate_two_phase_deadline(offset: u64, ttl: u64) -> Result<(), TwoPhaseDeadlineError> {
    if offset <= ttl {
        return Err(TwoPhaseDeadlineError::InsufficientOffset { offset, ttl });
    }

    Ok(())
}

