pub fn video_escrow_lockup(model_info: &ModelInfo, model_name: &str) -> Result<U256, String> {
    // Validate model has video pricing configured
    if model_info.video_fee_wei_per_pixel_second == 0 && model_info.video_base_fee_wei == 0 {
        return Err(format!(
            "Video model '{}' has no pricing configured (fee_per_pixel_second=0, base_fee=0)",
            model_name
        ));
    }

    // Worst case: max resolution at max duration
    let max_pixels = (VIDEO_MAX_WIDTH as u64) * (VIDEO_MAX_HEIGHT as u64);
    let max_duration_sec = VIDEO_MAX_DURATION_MS / 1000;

    // Calculate pixel-second fee using model-specific pricing
    let pixel_seconds = (max_pixels as u128) * (max_duration_sec as u128);
    let pixel_second_fee =
        U256::from(model_info.video_fee_wei_per_pixel_second) * U256::from(pixel_seconds);
    let base_fee = U256::from(model_info.video_base_fee_wei) + pixel_second_fee;

//! Scheduler contract state reading for scheduled transaction verification
//!
//! Reads Scheduler contract storage for validity constraint checks (C1-C11).
//! Uses similar storage reading patterns as ritual-async-registry crate.
//!
//! # Constraints Verified
//!
//! | ID | Constraint | Description |
//! |----|------------|-------------|
//! | C1 | Existence | callId exists in Scheduler |
//! | C2 | State | call.state == SCHEDULED |
//! | C3 | Index Bounds | executionIndex < numCalls |
//! | C4 | Min Block | block.number >= expectedBlock |
//! | C5 | Max Block (TTL) | block.number <= expectedBlock + TTL |
//! | C6 | Expiry | block.number <= overallExpiryBlock |
//! | C7 | Sender | msg.sender == SYSTEM_ACCOUNT |
//! | C8 | Target | tx.to == SCHEDULER |
//! | C9 | Funds | caller has sufficient funds in RitualWallet |
//! | C10 | Uniqueness | (callId, index) not executed before |
//! | C11 | Predicate | User-defined predicate returns true |

